import{_ as d,o,c as r,ae as a}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"왜 지금인가?","description":"","frontmatter":{},"headers":[],"relativePath":"part1-opening/why-now.md","filePath":"part1-opening/why-now.md"}'),e={name:"part1-opening/why-now.md"};function n(i,t,l,s,h,u){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="왜-지금인가" tabindex="-1">왜 지금인가? <a class="header-anchor" href="#왜-지금인가" aria-label="Permalink to &quot;왜 지금인가?&quot;">​</a></h1><h2 id="ai-코딩-도구의-폭발적-성장" tabindex="-1">AI 코딩 도구의 폭발적 성장 <a class="header-anchor" href="#ai-코딩-도구의-폭발적-성장" aria-label="Permalink to &quot;AI 코딩 도구의 폭발적 성장&quot;">​</a></h2><p>2024~2025년은 AI 코딩 도구의 <strong>골든 에이지</strong>입니다. 불과 2년 사이에 시장이 완전히 바뀌었습니다:</p><h3 id="타임라인" tabindex="-1">타임라인 <a class="header-anchor" href="#타임라인" aria-label="Permalink to &quot;타임라인&quot;">​</a></h3><table tabindex="0"><thead><tr><th>시기</th><th>이벤트</th></tr></thead><tbody><tr><td>2021.06</td><td>GitHub Copilot 프리뷰 출시 — AI 코딩 보조 시대 시작</td></tr><tr><td>2023.03</td><td>GPT-4 출시 — 코드 생성 품질 비약적 향상</td></tr><tr><td>2023.10</td><td>Cursor IDE 주목받기 시작</td></tr><tr><td>2024.06</td><td>Claude 3.5 Sonnet — &quot;개발자 최애 모델&quot; 등극</td></tr><tr><td>2024.10</td><td>Cursor, 시리즈 A $60M 투자 유치</td></tr><tr><td>2025.02</td><td>Andrej Karpathy, &quot;Vibe Coding&quot; 용어 제시</td></tr><tr><td>2025.03</td><td>Claude Code (CLI) 출시 — 에이전트 코딩 시대</td></tr><tr><td>2025.04</td><td>Gemini CLI, Codex CLI, Antigravity 등 경쟁 도구 등장</td></tr></tbody></table><h3 id="현재-주요-ai-코딩-도구" tabindex="-1">현재 주요 AI 코딩 도구 <a class="header-anchor" href="#현재-주요-ai-코딩-도구" aria-label="Permalink to &quot;현재 주요 AI 코딩 도구&quot;">​</a></h3><table tabindex="0"><thead><tr><th>도구</th><th>유형</th><th>특징</th></tr></thead><tbody><tr><td><strong>GitHub Copilot</strong></td><td>IDE 플러그인</td><td>VSCode 통합, 자동완성 중심</td></tr><tr><td><strong>Cursor</strong></td><td>AI IDE</td><td>AI 네이티브 에디터, Rules 시스템</td></tr><tr><td><strong>Claude Code</strong></td><td>CLI</td><td>에이전트 코딩, CLAUDE.md</td></tr><tr><td><strong>Gemini CLI</strong></td><td>CLI</td><td>Google Gemini 기반, GEMINI.md</td></tr><tr><td><strong>Antigravity</strong></td><td>AI IDE</td><td>Google 내부 도구 기반</td></tr><tr><td><strong>Codex CLI</strong></td><td>CLI</td><td>OpenAI Codex 기반</td></tr></tbody></table><h2 id="코딩의-민주화-논쟁" tabindex="-1">&quot;코딩의 민주화&quot; 논쟁 <a class="header-anchor" href="#코딩의-민주화-논쟁" aria-label="Permalink to &quot;&quot;코딩의 민주화&quot; 논쟁&quot;">​</a></h2><p>바이브 코딩을 둘러싼 두 가지 시각이 있습니다:</p><h3 id="낙관론-누구나-개발자가-되는-시대" tabindex="-1">낙관론: &quot;누구나 개발자가 되는 시대&quot; <a class="header-anchor" href="#낙관론-누구나-개발자가-되는-시대" aria-label="Permalink to &quot;낙관론: &quot;누구나 개발자가 되는 시대&quot;&quot;">​</a></h3><ul><li>프로그래밍 언어를 몰라도 앱을 만들 수 있다</li><li>프로토타이핑 속도가 10배 빨라진다</li><li>개발자 수요-공급 격차를 해소할 수 있다</li></ul><h3 id="현실론-잘-쓰려면-엔지니어링이-필요하다" tabindex="-1">현실론: &quot;잘 쓰려면 엔지니어링이 필요하다&quot; <a class="header-anchor" href="#현실론-잘-쓰려면-엔지니어링이-필요하다" aria-label="Permalink to &quot;현실론: &quot;잘 쓰려면 엔지니어링이 필요하다&quot;&quot;">​</a></h3><ul><li>AI가 생성한 코드의 <strong>품질 편차</strong>가 크다</li><li>복잡한 프로젝트에서는 AI가 <strong>맥락을 잃는다</strong></li><li>&quot;코드는 나왔는데 유지보수가 불가능한&quot; 상황이 빈번</li></ul><div class="info custom-block"><p class="custom-block-title">🎯 이 워크숍의 입장</p><p><strong>둘 다 맞습니다.</strong></p><p>바이브 코딩은 강력하지만, &quot;잘&quot; 하려면 체계가 필요합니다. 그 체계가 바로 <strong>프롬프트 → 컨텍스트 → 하네스</strong> 3세대 엔지니어링입니다.</p></div>',14)])])}const g=d(e,[["render",n]]);export{c as __pageData,g as default};
